// Payload z LeadModal demo: { name, email, phone, clients, employees, offices, source, timestamp }
const d = $input.first().json.body ?? $input.first().json;

const esc = (s) => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const name = esc(d.name) || '(brak)';
const email = esc(d.email) || '(brak)';
const phone = esc(d.phone) || '(nie podano)';
const clients = esc(d.clients) || '(nie podano)';
const employees = esc(d.employees) || '(nie podano)';
const offices = esc(d.offices) || '(nie podano)';
const when = d.timestamp ? new Date(d.timestamp).toLocaleString('pl-PL', { timeZone: 'Europe/Warsaw' }) : new Date().toLocaleString('pl-PL', { timeZone: 'Europe/Warsaw' });

const html = `
<h2>\uD83E\uDD81 Nowy lead z demo Brakomatu</h2>
<table cellpadding="6" style="border-collapse:collapse;font-family:sans-serif">
  <tr><td><b>Imi\u0119 i nazwisko</b></td><td>${name}</td></tr>
  <tr><td><b>Email</b></td><td><a href="mailto:${email}">${email}</a></td></tr>
  <tr><td><b>Telefon</b></td><td>${phone}</td></tr>
  <tr><td><b>Liczba klient\u00f3w</b></td><td>${clients}</td></tr>
  <tr><td><b>Pracownicy</b></td><td>${employees}</td></tr>
  <tr><td><b>Oddzia\u0142y</b></td><td>${offices}</td></tr>
  <tr><td><b>\u0179r\u00f3d\u0142o</b></td><td>${esc(d.source) || 'brakomat-demo'}</td></tr>
  <tr><td><b>Data</b></td><td>${when}</td></tr>
</table>
<p>Sugerowany pakiet: <b>${d.clients === '100+' ? 'Pakiet 3' : d.clients === '50-100' ? 'Pakiet 2/3' : d.clients === '20-50' ? 'Pakiet 2' : 'Pakiet 1'}</b></p>`;

return [{ json: {
  subject: `\uD83E\uDD81 Lead z demo Brakomat: ${name}${d.phone ? ' \u2618 tel: ' + phone : ''}`,
  html,
  leadEmail: d.email ?? null,
} }];
